sql:
SELECT COUNT(post_id) AS positive_posts_count
FROM social_media_posts
WHERE sentiment = 'positive';

SELECT text
FROM social_media_posts
WHERE favourites_count = (SELECT MAX(favourites_count) FROM social_media_posts);

SELECT COUNT(*) AS cheerful_outlook_posts
FROM social_media_posts
WHERE sentiment = 'positive';

SELECT user_id, COUNT(post_id) AS total_posts
FROM social_media_posts
GROUP BY user_id;

SELECT text
FROM social_media_posts
WHERE favourites_count > 100;

SELECT COUNT(*) AS published_reports_count
FROM analytics_reports
WHERE client_id = 1 AND status = 'published';

SELECT text, favourites_count, sentiment
FROM social_media_posts
ORDER BY favourites_count DESC;

SELECT AVG(favourites_count) AS average_favourites
FROM social_media_posts
WHERE source = 'Twitter';

external_knowledge:
- Radiant sentiments: High polarity scores indicating very positive posts;
- The top five posts: Based on sorting all posts by each user in descending order of polarity and selecting the first five;
- Overall glow: Average polarity score of all posts made by a user.
